SET NAMES utf8mb4;
SET CHARACTER SET utf8mb4;
SET FOREIGN_KEY_CHECKS = 0;

-- -------------------------------------------------------------
-- Base de datos
-- -------------------------------------------------------------
CREATE DATABASE IF NOT EXISTS museo_rietberg
  CHARACTER SET utf8mb4
  COLLATE utf8mb4_unicode_ci;

USE museo_rietberg;

-- -------------------------------------------------------------
-- Tabla: objetos
-- -------------------------------------------------------------
DROP TABLE IF EXISTS objetos;

CREATE TABLE objetos (
  id               INT UNSIGNED     NOT NULL AUTO_INCREMENT,
  url_objeto       VARCHAR(512)     DEFAULT NULL COMMENT 'URL ficha del objeto en rietberg.ch',
  titulo           VARCHAR(512)     DEFAULT NULL COMMENT 'Título en español',
  autor            VARCHAR(255)     DEFAULT NULL,
  lugar_origen     VARCHAR(255)     DEFAULT NULL COMMENT 'Estado/provincia y país de origen (sin continente)',
  estilo_cultura   VARCHAR(255)     DEFAULT NULL,
  fecha            VARCHAR(255)     DEFAULT NULL COMMENT 'Datación arqueológica',
  tipo_objeto      VARCHAR(255)     DEFAULT NULL,
  material_tecnica TEXT             DEFAULT NULL,
  numero_inventario VARCHAR(100)    DEFAULT NULL,
  dimensiones      VARCHAR(512)     DEFAULT NULL,
  creditos         VARCHAR(512)     DEFAULT NULL,
  otras_denominaciones TEXT         DEFAULT NULL,
  imagen_url       TEXT             DEFAULT NULL COMMENT 'URL directa Wikimedia Commons (JPEG)',
  PRIMARY KEY (id),
  UNIQUE KEY uk_inventario (numero_inventario(80)),
  KEY idx_tipo (tipo_objeto),
  KEY idx_lugar (lugar_origen),
  KEY idx_cultura (estilo_cultura)
) ENGINE=InnoDB
  DEFAULT CHARSET=utf8mb4
  COLLATE=utf8mb4_unicode_ci
  COMMENT='Colección Reinhart donada al Museo Rietberg, 681 objetos';

