-- -------------------------------------------------------------
-- Vista opcional: solo objetos con imagen disponible
-- -------------------------------------------------------------
CREATE OR REPLACE VIEW objetos_con_imagen AS
  SELECT id, titulo, autor, lugar_origen, estilo_cultura, fecha,
         tipo_objeto, numero_inventario, imagen_url
  FROM   objetos
  WHERE  imagen_url IS NOT NULL;

SET FOREIGN_KEY_CHECKS = 1;
-- Fin del script
